   691→	return signal.v;
   692→}
   693→
   694→/** @param {Derived} derived */
   695→function depends_on_old_values(derived) {
   696→	if (derived.v === UNINITIALIZED) return true; // we don't know, so assume the worst
   697→	if (derived.deps === null) return false;
   698→
   699→	for (const dep of derived.deps) {
   700→		if (old_values.has(dep)) {
   701→			return true;
   702→		}
   703→
   704→		if ((dep.f & DERIVED) !== 0 && depends_on_old_values(/** @type {Derived} */ (dep))) {
   705→			return true;
   706→		}
   707→	}
   708→
   709→	return false;
   710→}
   711→
   712→/**
   713→ * Like `get`, but checks for `undefined`. Used for `var` declarations because they can be accessed before being declared
   714→ * @template V
