   716→ * @returns {V | undefined}
   717→ */
   718→export function safe_get(signal) {
   719→	return signal && get(signal);
   720→}
   721→
   722→/**
   723→ * Capture an array of all the signals that are read when `fn` is called
   724→ * @template T
   725→ * @param {() => T} fn
   726→ */
   727→function capture_signals(fn) {
   728→	var previous_captured_signals = captured_signals;
   729→	captured_signals = new Set();
   730→
   731→	var captured = captured_signals;
   732→	var signal;
   733→
   734→	try {
   735→		untrack(fn);
   736→		if (previous_captured_signals !== null) {
   737→			for (signal of captured_signals) {
   738→				previous_captured_signals.add(signal);
   739→			}
   740→		}
   741→	} finally {
   742→		captured_signals = previous_captured_signals;
   743→	}
   744→
   745→	return captured;
   746→}
   747→
   748→/**
   749→ * Invokes a function and captures all signals that are read during the invocation,
   750→ * then invalidates them.
   751→ * @param {() => any} fn
