   773→ * @template T
   774→ * @param {() => T} fn
   775→ * @returns {T}
   776→ */
   777→export function untrack(fn) {
   778→	var previous_untracking = untracking;
   779→	try {
   780→		untracking = true;
   781→		return fn();
   782→	} finally {
   783→		untracking = previous_untracking;
   784→	}
   785→}
   786→
   787→const STATUS_MASK = ~(DIRTY | MAYBE_DIRTY | CLEAN);
   788→
   789→/**
   790→ * @param {Signal} signal
   791→ * @param {number} status
   792→ * @returns {void}
   793→ */
   794→export function set_signal_status(signal, status) {
   795→	signal.f = (signal.f & STATUS_MASK) | status;
   796→}
   797→
   798→/**
   799→ * @param {Record<string, unknown>} obj
   800→ * @param {string[]} keys
   801→ * @returns {Record<string, unknown>}
   802→ */
   803→export function exclude_from_object(obj, keys) {
   804→	/** @type {Record<string, unknown>} */
   805→	var result = {};
   806→
   807→	for (var key in obj) {
   808→		if (!keys.includes(key)) {
   809→			result[key] = obj[key];
   810→		}
   811→	}
   812→
   813→	return result;
   814→}
   815→
   816→/**
   817→ * Possibly traverse an object and read all its properties so that they're all reactive in case this is `$state`.
   818→ * Does only check first level of an object for performance reasons (heuristic should be good for 99% of all cases).
   819→ * @param {any} value
   820→ * @returns {void}
   821→ */
   822→export function deep_read_state(value) {
   823→	if (typeof value !== 'object' || !value || value instanceof EventTarget) {
   824→		return;
   825→	}
   826→
   827→	if (STATE_SYMBOL in value) {
   828→		deep_read(value);
   829→	} else if (!Array.isArray(value)) {
   830→		for (let key in value) {
   831→			const prop = value[key];
   832→			if (typeof prop === 'object' && prop && STATE_SYMBOL in prop) {
   833→				deep_read(prop);
   834→			}
   835→		}
   836→	}
   837→}
   838→
   839→/**
   840→ * Deeply traverse an object and read all its properties
   841→ * so that they're all reactive in case this is `$state`
   842→ * @param {any} value
   843→ * @param {Set<any>} visited
   844→ * @returns {void}
   845→ */
   846→export function deep_read(value, visited = new Set()) {
   847→	if (
   848→		typeof value === 'object' &&
   849→		value !== null &&
   850→		// We don't want to traverse DOM elements
   851→		!(value instanceof EventTarget) &&
   852→		!visited.has(value)
   853→	) {
   854→		visited.add(value);
   855→		// When working with a possible SvelteDate, this
   856→		// will ensure we capture changes to it.
   857→		if (value instanceof Date) {
   858→			value.getTime();
   859→		}
