   861→			try {
   862→				deep_read(value[key], visited);
   863→			} catch (e) {
   864→				// continue
   865→			}
   866→		}
   867→		const proto = get_prototype_of(value);
   868→		if (
   869→			proto !== Object.prototype &&
   870→			proto !== Array.prototype &&
   871→			proto !== Map.prototype &&
   872→			proto !== Set.prototype &&
   873→			proto !== Date.prototype
   874→		) {
   875→			const descriptors = get_descriptors(proto);
   876→			for (let key in descriptors) {
   877→				const get = descriptors[key].get;
   878→				if (get) {
   879→					try {
   880→						get.call(value);
   881→					} catch (e) {
   882→						// continue
   883→					}
   884→				}
   885→			}
   886→		}
   887→	}
   888→}
