import { effect_root } from './reactivity/effects';
import { source, set } from './reactivity/sources';

test('effects should run synchronously with flushSync in effect_root', () => {
	const log: number[] = [];

	const cleanup = effect_root(() => {
		const count = source(0);

		// Create an effect that logs the count
		const effect_fn = () => {
			log.push(count.v);
		};

		// Manual effect creation similar to $effect
		import('./reactivity/effects').then(({ user_effect }) => {
			user_effect(effect_fn);
		});

		// use flushSync to execute all pending effects synchronously
		flushSync();
		assert.deepEqual(log, [0]);

		set(count, 1);
		flushSync();
		assert.deepEqual(log, [0, 1]);
	});

	cleanup();
});

