import { test, assert, afterEach } from 'vitest';
import { flushSync, clear } from './reactivity/batch.js';
import { effect_root } from './reactivity/effects.js';
import { source, set } from './reactivity/sources.js';
import { user_effect } from './reactivity/effects.js';

afterEach(() => {
	clear();
});

test('effects should run synchronously with flushSync in effect_root', () => {
	const log: number[] = [];

	const cleanup = effect_root(() => {
		const count = source(0);

		// Create a user effect (similar to $effect)
		user_effect(() => {
			const value = count.v;
			console.log('Effect running, count.v =', value);
			log.push(value);
		});

		// use flushSync to execute all pending effects synchronously
		console.log('Before first flushSync, log =', log);
		flushSync();
		console.log('After first flushSync, log =', log);
		assert.deepEqual(log, [0], 'Effect should have run after first flushSync');

		set(count, 1);
		console.log('After set, before second flushSync, log =', log);
		flushSync();
		console.log('After second flushSync, log =', log);
		assert.deepEqual(log, [0, 1], 'Effect should have run after second flushSync');
	});

	cleanup();
});

